using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed — EF Core 9 Cosmos provider throws at startup.
        // Manage indexing via the Azure Portal or IaC (Bicep/Terraform).

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve "Discriminator" property name used by existing 500K documents.
            // EF Core 9 defaults to "$type"; without this, queries won't match old data
            // and direct SQL filtering on c.Discriminator will break.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve compound id format "Product|123" used by existing documents.
            // EF Core 9 defaults to bare key ("123"); without this, FindAsync and
            // point-reads against old documents will fail.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

